# Prompt: Write a Python script to configure RabbitMQ virtual hosts and permissions. Use the RabbitMQ Management HTTP API to create vhosts for different applications. Set up users and grant permissions for queue operations. This is for our multi-tenant message broker setup.
# Category: rabbitmq_vhost_isolation

import requests
import json

RABBITMQ_API_URL = 'http://localhost:15672/api'  # Change this to your RabbitMQ Management API URL
RABBITMQ_ADMIN_USER = 'admin'  # Change to your admin username
RABBITMQ_ADMIN_PASSWORD = 'password'  # Change to your admin password

vhosts = ['app1', 'app2', 'app3']  # List of virtual hosts
users = [
    {'name': 'user1', 'password': 'password1', 'vhost': 'app1'},
    {'name': 'user2', 'password': 'password2', 'vhost': 'app2'},
    {'name': 'user3', 'password': 'password3', 'vhost': 'app3'}
]

def create_vhost(vhost):
    response = requests.put(f'{RABBITMQ_API_URL}/vhosts/{vhost}', auth=(RABBITMQ_ADMIN_USER, RABBITMQ_ADMIN_PASSWORD))
    if response.status_code == 201:
        print(f'Created vhost: {vhost}')
    else:
        print(f'Failed to create vhost: {vhost}, Status Code: {response.status_code}')

def create_user(user):
    response = requests.put(f'{RABBITMQ_API_URL}/users/{user["name"]}', 
                            auth=(RABBITMQ_ADMIN_USER, RABBITMQ_ADMIN_PASSWORD), 
                            json={'password': user['password'], 'tags': ''})
    if response.status_code == 201:
        print(f'Created user: {user["name"]}')
    else:
        print(f'Failed to create user: {user["name"]}, Status Code: {response.status_code}')

def set_permissions(user):
    permissions = {
        'configure': '.*',
        'write': '.*',
        'read': '.*'
    }
    response = requests.put(f'{RABBITMQ_API_URL}/permissions/{user["vhost"]}/{user["name"]}', 
                            auth=(RABBITMQ_ADMIN_USER, RABBITMQ_ADMIN_PASSWORD), 
                            json=permissions)
    if response.status_code == 204:
        print(f'Set permissions for user: {user["name"]} on vhost: {user["vhost"]}')
    else:
        print(f'Failed to set permissions for user: {user["name"]}, Status Code: {response.status_code}')

for vhost in vhosts:
    create_vhost(vhost)

for user in users:
    create_user(user)
    set_permissions(user)